{
  "terms": [
    {
      "term": "Transposition",
      "simpleDefinition": "The process of rearranging a formula to move a specific variable to one side of the equals sign.",
      "anchor": "Moving a multiplier across the equals sign turns it into a divisor (and vice versa).",
      "misconception": "Believing you can move a term to the other side of the equation without changing its mathematical operation."
    },
    {
      "term": "Indices (Powers of 10)",
      "simpleDefinition": "A shorthand method of writing very large or very small numbers using powers of ten, such as kilo or milli.",
      "anchor": "10 to the power of 3 (10³) represents 1,000 (kilo), while 10 to the power of -3 (10⁻³) represents 0.001 (milli).",
      "misconception": "Thinking that 10³ means 10 multiplied by 3 (30) rather than 10 multiplied by itself three times (1,000)."
    },
    {
      "term": "Pythagoras’ Theorem",
      "simpleDefinition": "A mathematical rule stating that in a right-angled triangle, the square of the longest side is equal to the sum of the squares of the other two sides.",
      "anchor": "Used to calculate total Impedance (Z) when you know the Resistance (R) and Reactance (X).",
      "misconception": "Forgetting to perform the final square root calculation after adding the two squared values together."
    },
    {
      "term": "Trigonometry (SOHCAHTOA)",
      "simpleDefinition": "The study of the relationships between the sides and angles of triangles, specifically using Sine, Cosine, and Tangent.",
      "anchor": "Using Cosine (Adjacent / Hypotenuse) to determine the Power Factor of an AC circuit.",
      "misconception": "Selecting the wrong trigonometric ratio, such as using Sine when the calculation requires the relationship between the adjacent side and the hypotenuse."
    },
    {
      "term": "Algebra",
      "simpleDefinition": "A branch of mathematics where letters and symbols are used to represent numbers in formulas and equations.",
      "anchor": "In the formula V = I × R, the letters are variables representing Voltage, Current, and Resistance.",
      "misconception": "Treating the letters in a formula as static labels rather than placeholders for numerical values that can be manipulated."
    },
    {
      "term": "Statistics (Mean)",
      "simpleDefinition": "The mathematical average of a set of numbers, found by adding them all up and dividing by how many numbers there are.",
      "anchor": "Calculating the average insulation resistance reading across multiple circuit tests to identify trends.",
      "misconception": "Confusing the 'mean' (the calculated average) with the 'median' (the middle number in a sorted list)."
    }
  ],
  "anchorPhrases": [
    "Change the side, change the operation.",
    "Square root the sum of the squares for the hypotenuse.",
    "SOHCAHTOA: Sine-Opposite, Cosine-Adjacent, Tangent-Opposite.",
    "Powers of ten scale our units from milli to mega."
  ],
  "misconceptionTargets": [
    "Moving a multiplier across the equals sign and keeping it as a multiplier.",
    "Calculating 10 to the power of 3 as 30.",
    "Omitting the square root step in Pythagoras' Theorem.",
    "Using Sine instead of Cosine for Power Factor calculations.",
    "Confusing the mean average with the median value in test data."
  ]
}
}

